class Solution:
    def largestMultipleOfThree(self, digits) -> str:
        # Frequency-array formulation (no sorting/popping a list): independent of the
        # optimal solution's sort-and-splice approach, same asymptotic cost.
        freq = [0] * 10
        for d in digits:
            freq[d] += 1
        total = sum(digits)
        r = total % 3

        def remove_smallest_with_mod(mod):
            for v in range(10):
                if v % 3 == mod and freq[v] > 0:
                    freq[v] -= 1
                    return True
            return False

        if r == 1:
            if not remove_smallest_with_mod(1):
                remove_smallest_with_mod(2)
                remove_smallest_with_mod(2)
        elif r == 2:
            if not remove_smallest_with_mod(2):
                remove_smallest_with_mod(1)
                remove_smallest_with_mod(1)

        result = []
        for v in range(9, -1, -1):
            result.extend([str(v)] * freq[v])
        if not result:
            return ''
        if result[0] == '0':
            return '0'
        return ''.join(result)

