class Solution:
    def largestMultipleOfThree(self, digits) -> str:
        digits = sorted(digits, reverse=True)
        total = sum(digits)
        r = total % 3

        def remove_smallest_with_mod(mod):
            for i in range(len(digits) - 1, -1, -1):
                if digits[i] % 3 == mod:
                    digits.pop(i)
                    return True
            return False

        if r == 1:
            if not remove_smallest_with_mod(1):
                remove_smallest_with_mod(2)
                remove_smallest_with_mod(2)
        elif r == 2:
            if not remove_smallest_with_mod(2):
                remove_smallest_with_mod(1)
                remove_smallest_with_mod(1)

        if not digits:
            return ''
        if digits[0] == 0:
            return '0'
        return ''.join(map(str, digits))

