var largestMultipleOfThree = function(digits) {
    digits = digits.slice().sort((a, b) => b - a);
    const total = digits.reduce((a, b) => a + b, 0);
    const r = total % 3;

    const removeSmallestWithMod = (mod) => {
        for (let i = digits.length - 1; i >= 0; i--) {
            if (digits[i] % 3 === mod) {
                digits.splice(i, 1);
                return true;
            }
        }
        return false;
    };

    if (r === 1) {
        if (!removeSmallestWithMod(1)) {
            removeSmallestWithMod(2);
            removeSmallestWithMod(2);
        }
    } else if (r === 2) {
        if (!removeSmallestWithMod(2)) {
            removeSmallestWithMod(1);
            removeSmallestWithMod(1);
        }
    }

    if (digits.length === 0) return '';
    if (digits[0] === 0) return '0';
    return digits.join('');
};
